const crypto = require('crypto');
const secret = $env.REVIEW_HMAC_SECRET || 'fallback-secret';
const baseUrl = 'https://n8n.rodinah.dev/webhook/checklist-response';
const metabaseUrl = 'http://hal-srvr:3002/dashboard/6';

// Grab FY from the first item (all items share the same FY from the query)
const items = $input.all().filter(r => r.json && r.json.group_code != null);
const fy_year = 2025;

function makeToken(groupCode, fy, resp) {
  return crypto.createHmac('sha256', secret)
    .update(`${groupCode}|${fy}|${resp}`)
    .digest('hex');
}

function makeLink(groupCode, fy, resp) {
  const token = makeToken(groupCode, fy, resp);
  const enc = encodeURIComponent(groupCode);
  return `${baseUrl}?group=${enc}&fy=${fy}&resp=${resp}&token=${token}`;
}

function responseIndicator(current, resp) {
  if (current === resp) return ' <strong style="font-size:11px;color:#64748b">(current)</strong>';
  return '';
}

function yesStyle(current) {
  const active = current === 'YES';
  return active
    ? 'background:#16a34a;color:#fff;padding:7px 14px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:700;display:inline-block'
    : 'background:#f0fdf4;color:#16a34a;border:1px solid #86efac;padding:6px 13px;border-radius:4px;text-decoration:none;font-size:13px;display:inline-block';
}

function noStyle(current) {
  const active = current === 'NO';
  return active
    ? 'background:#dc2626;color:#fff;padding:7px 14px;border-radius:4px;text-decoration:none;font-size:13px;font-weight:700;display:inline-block'
    : 'background:#fef2f2;color:#dc2626;border:1px solid #fca5a5;padding:6px 13px;border-radius:4px;text-decoration:none;font-size:13px;display:inline-block';
}

// Group items by section
const sections = {};
for (const item of items) {
  const d = item.json;
  if (!sections[d.section]) sections[d.section] = [];
  sections[d.section].push(d);
}

const sectionOrder = ['Income', 'Deductions', 'Property', 'Super', 'Health', 'Government'];

let sectionHtml = '';
for (const section of sectionOrder) {
  const rows = sections[section];
  if (!rows || rows.length === 0) continue;

  const rowHtml = rows.map(d => {
    const yesLink = makeLink(d.group_code, fy_year, 'YES');
    const noLink  = makeLink(d.group_code, fy_year, 'NO');
    const current = d.current_response || 'UNKNOWN';
    const unknownBadge = current === 'UNKNOWN'
      ? '<span style="font-size:10px;background:#fef9c3;color:#854d0e;padding:2px 6px;border-radius:3px;margin-left:6px">NOT ANSWERED</span>'
      : '';
    return `
    <tr style="border-bottom:1px solid #f1f5f9">
      <td style="padding:12px 16px;font-size:14px;color:#1e293b;line-height:1.4">
        ${d.applicability_question}${unknownBadge}
      </td>
      <td style="padding:12px 16px;white-space:nowrap">
        <a href="${yesLink}" style="${yesStyle(current)}">&#10003;&nbsp;YES</a>
        &nbsp;
        <a href="${noLink}" style="${noStyle(current)}">&#10007;&nbsp;NO</a>
      </td>
    </tr>`;
  }).join('');

  sectionHtml += `
  <h3 style="margin:28px 0 8px;color:#0f172a;font-size:15px;text-transform:uppercase;letter-spacing:.05em;padding:0 24px">${section}</h3>
  <table style="width:100%;border-collapse:collapse;border-top:2px solid #e2e8f0">
    <tbody>${rowHtml}
    </tbody>
  </table>`;
}

const answeredCount  = items.filter(r => r.json.current_response !== 'UNKNOWN').length;
const totalCount     = items.length;
const progressPct    = Math.round(100 * answeredCount / totalCount);

const progressBar = `
<div style="background:#e2e8f0;border-radius:4px;height:8px;margin:12px 24px 4px">
  <div style="background:#3b82f6;border-radius:4px;height:8px;width:${progressPct}%"></div>
</div>
<p style="color:#64748b;font-size:12px;margin:0 24px 16px">
  ${answeredCount} of ${totalCount} questions answered
</p>`;

const html = `<!DOCTYPE html>
<html>
<head><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:20px;background:#f8fafc">
<div style="max-width:720px;margin:0 auto;background:#fff;border-radius:10px;box-shadow:0 1px 4px rgba(0,0,0,.1);overflow:hidden">

  <div style="background:#1e40af;padding:24px">
    <h1 style="color:#fff;margin:0;font-size:20px">&#128203; Tax Return Checklist — FY${fy_year}</h1>
    <p style="color:#bfdbfe;margin:6px 0 0;font-size:14px">
      Please confirm which items apply to your ${fy_year - 1}–${fy_year} return.
      Filled answers are shown bold — click to change at any time.
    </p>
  </div>

  ${progressBar}

  ${sectionHtml}

  <div style="padding:20px 24px;border-top:1px solid #e2e8f0;text-align:center">
    <a href="${metabaseUrl}" style="color:#1e40af;font-size:13px;text-decoration:none">
      &#128202; View Completeness Dashboard in Metabase
    </a>
  </div>

</div>
</body>
</html>`;

const subject = `TC Checklist FY${fy_year} — ${answeredCount}/${totalCount} questions answered`;

return [{ json: { html, subject, answeredCount, totalCount, fy_year } }];
